<?php\n\nnamespace App\Federation;\n\nuse Psr\Log\LoggerInterface;\nuse GuzzleHttp\ClientInterface;\nuse App\Security\SignatureHandler;\nuse App\Exceptions\FederationException;\n\nclass FederationClient\n{\n    private ClientInterface $httpClient;\n    private LoggerInterface $logger;\n    private SignatureHandler $signatureHandler;\n    private string $localNodeIdentifier;\n\n    public function __construct(\n        ClientInterface $httpClient,\n        LoggerInterface $logger,\n        SignatureHandler $signatureHandler,\n        string $localNodeIdentifier\n    ) {\n        $this->httpClient = $httpClient;\n        $this->logger = $logger;\n        $this->signatureHandler = $signatureHandler;\n        $this->localNodeIdentifier = $localNodeIdentifier;\n    }\n\n    /**\n     * Sends a document or update payload to a remote federated node.\n     *\n     * @param string $remoteNodeUrl The base URL of the remote node.\n     * @param string $endpoint The API endpoint on the remote node (e.g., "/documents/sync").\n     * @param array $payload The data payload to send.\n     * @param array $headers Optional additional headers.\n     * @return array The response from the remote node.\n     * @throws FederationException If the request fails or returns an error.\n     */\n    public function sendPayload(string $remoteNodeUrl, string $endpoint, array $payload, array $headers = []): array\n    {\n        $fullUrl = rtrim($remoteNodeUrl, '/') . '/' . ltrim($endpoint, '/');\n        $signedPayload = $this->signatureHandler->signPayload($payload, $this->localNodeIdentifier);\n\n        $requestHeaders = array_merge([\n            'Content-Type' => 'application/json',\n            'X-Node-Identifier' => $this->localNodeIdentifier,\n            'X-Signature' => $signedPayload['signature'],\n            'X-Timestamp' => $signedPayload['timestamp'],\n        ], $headers);\n\n        try {\n            $this->logger->info("Sending payload to remote node.", ['url' => $fullUrl, 'endpoint' => $endpoint, 'node' => $this->localNodeIdentifier]);\n            $response = $this->httpClient->post($fullUrl, [\n                'headers' => $requestHeaders,\n                'json' => $signedPayload['data'], // Send the original data, signature is in headers\n                'timeout' => 10 // 10-second timeout\n            ]);\n\n            $statusCode = $response->getStatusCode();\n            $responseBody = json_decode((string) $response->getBody(), true);\n\n            if ($statusCode >= 400) {\n                $errorMessage = $responseBody['message'] ?? 'Unknown error from remote node.';\n                $this->logger->error("Received error response from remote node.", ['url' => $fullUrl, 'status' => $statusCode, 'error' => $errorMessage]);\n                throw new FederationException("Remote node error: {$errorMessage}", $statusCode);\n            }\n\n            $this->logger->info("Successfully sent payload to remote node.", ['url' => $fullUrl, 'status' => $statusCode]);\n            return $responseBody;\n\n        } catch (\GuzzleHttp\Exception\ConnectException $e) {\n            $this->logger->critical("Failed to connect to remote federated node.", ['url' => $fullUrl, 'error' => $e->getMessage()]);\n            throw new FederationException("Network connection failure to remote node: " . $e->getMessage(), 0, $e);\n        } catch (\GuzzleHttp\Exception\RequestException $e) {\n            $statusCode = $e->getResponse() ? $e->getResponse()->getStatusCode() : 0;\n            $responseBody = $e->getResponse() ? json_decode((string) $e->getResponse()->getBody(), true) : ['message' => 'No response body'];\n            $this->logger->error("Request error communicating with remote federated node.", ['url' => $fullUrl, 'status' => $statusCode, 'error' => $responseBody['message'] ?? $e->getMessage()]);\n            throw new FederationException("Request error with remote node: " . ($responseBody['message'] ?? $e->getMessage()), $statusCode, $e);\n        } catch (\Exception $e) {\n            $this->logger->error("An unexpected error occurred during federation request.", ['url' => $fullUrl, 'error' => $e->getMessage()]);\n            throw new FederationException("Unexpected federation error: " . $e->getMessage(), 0, $e);\n        }\n    }\n\n    /**\n     * Requests specific data (e.g., a document, metadata) from a remote node.\n     *\n     * @param string $remoteNodeUrl The base URL of the remote node.\n     * @param string $endpoint The API endpoint for data retrieval.\n     * @param array $queryParams Query parameters for the GET request.\n     * @param array $headers Optional additional headers.\n     * @return array The retrieved data.\n     * @throws FederationException If the request fails.\n     */\n    public function requestData(string $remoteNodeUrl, string $endpoint, array $queryParams = [], array $headers = []): array\n    {\n        $fullUrl = rtrim($remoteNodeUrl, '/') . '/' . ltrim($endpoint, '/');\n        $signedQueryParams = $this->signatureHandler->signPayload($queryParams, $this->localNodeIdentifier);\n\n        $requestHeaders = array_merge([\n            'X-Node-Identifier' => $this->localNodeIdentifier,\n            'X-Signature' => $signedQueryParams['signature'],\n            'X-Timestamp' => $signedQueryParams['timestamp']\n        ], $headers);\n\n        try {\n            $this->logger->info("Requesting data from remote node.", ['url' => $fullUrl, 'endpoint' => $endpoint, 'node' => $this->localNodeIdentifier, 'params' => $queryParams]);\n            $response = $this->httpClient->get($fullUrl, [\n                'headers' => $requestHeaders,\n                'query' => $signedQueryParams['data'],\n                'timeout' => 10\n            ]);\n\n            $statusCode = $response->getStatusCode();\n            $responseBody = json_decode((string) $response->getBody(), true);\n\n            if ($statusCode !== 200) {\n                $errorMessage = $responseBody['message'] ?? 'Unknown error retrieving data from remote node.';\n                $this->logger->error("Received non-200 status for data request.", ['url' => $fullUrl, 'status' => $statusCode, 'error' => $errorMessage]);\n                throw new FederationException("Remote node data retrieval error: {$errorMessage}", $statusCode);\n            }\n\n            $this->logger->info("Successfully retrieved data from remote node.", ['url' => $fullUrl, 'status' => $statusCode]);\n            return $responseBody;\n\n        } catch (\GuzzleHttp\Exception\ConnectException $e) {\n            $this->logger->critical("Failed to connect for data retrieval from remote federated node.", ['url' => $fullUrl, 'error' => $e->getMessage()]);\n            throw new FederationException("Network connection failure for data retrieval: " . $e->getMessage(), 0, $e);\n        } catch (\GuzzleHttp\Exception\RequestException $e) {\n            $statusCode = $e->getResponse() ? $e->getResponse()->getStatusCode() : 0;\n            $responseBody = $e->getResponse() ? json_decode((string) $e->getResponse()->getBody(), true) : ['message' => 'No response body'];\n            $this->logger->error("Request error retrieving data from remote federated node.", ['url' => $fullUrl, 'status' => $statusCode, 'error' => $responseBody['message'] ?? $e->getMessage()]);\n            throw new FederationException("Request error retrieving data: " . ($responseBody['message'] ?? $e->getMessage()), $statusCode, $e);\n        } catch (\Exception $e) {\n            $this->logger->error("An unexpected error occurred during data retrieval from remote node.", ['url' => $fullUrl, 'error' => $e->getMessage()]);\n            throw new FederationException("Unexpected data retrieval error: " . $e->getMessage(), 0, $e);\n        }\n    }\n}